// ── EMAILJS CONFIGURATION ────────────────────────────────────────
// SETUP: Create a free account at https://emailjs.com
// Then replace these values with your own credentials.
const EMAILJS_CONFIG = {
  publicKey:  'YOUR_PUBLIC_KEY',          // From EmailJS Dashboard → Account
  serviceId:  'service_sla_academy',      // From EmailJS → Email Services
  templateId: 'template_welcome_student', // From EmailJS → Email Templates
};
// ── EMAIL TEMPLATE VARIABLES (configure in EmailJS dashboard) ────
// {{to_name}} {{to_email}} {{admission_number}} {{level_name}}
// {{language_name}} {{enrol_fee}} {{contact_email}} {{contact_phone}}

let _emailJSReady = false;
async function sendRegistrationEmail(student) {
  if (typeof emailjs === 'undefined') {
    console.warn('[SLA Email] EmailJS not loaded — skipping welcome email.');
    return;
  }
  if (!EMAILJS_CONFIG.publicKey || EMAILJS_CONFIG.publicKey === 'YOUR_PUBLIC_KEY') {
    console.warn('[SLA Email] EmailJS not configured. Update sea-curriculum.js EMAILJS_CONFIG.');
    return;
  }
  try {
    if (!_emailJSReady) {
      emailjs.init({ publicKey: EMAILJS_CONFIG.publicKey });
      _emailJSReady = true;
    }
    const langName = student.language === 'swahili' ? 'Kiswahili' : 'English';
    const levelName = SEA && SEA.levels ? SEA.levels[student.enrolledLevel - 1].name : 'Level ' + student.enrolledLevel;
    await emailjs.send(EMAILJS_CONFIG.serviceId, EMAILJS_CONFIG.templateId, {
      to_name:          student.name,
      to_email:         student.email,
      admission_number: student.admissionNumber,
      level_name:       levelName,
      language_name:    langName,
      enrol_fee:        (typeof enrollFee === 'function' ? enrollFee(student.enrolledLevel) : '—'),
      contact_email:    SEA_CONTACT ? SEA_CONTACT.email : 'info@studylanguage.ac.ke',
      contact_phone:    SEA_CONTACT ? SEA_CONTACT.phone : '+254 735 567 826',
      academy_name:     'Study Language Academy',
    });
    console.log('[SLA Email] Welcome email sent to', student.email);
    if (typeof showToast === 'function') showToast('Welcome email sent to ' + student.email, 'success');
  } catch (err) {
    console.warn('[SLA Email] Could not send email:', err && err.text ? err.text : err);
  }
}

