// ── Helper: Get weekly test for given params ───────────────────
function getWeeklyTest(lang, level, week) {
  try {
    return SEA_WEEKLY_TESTS[lang]?.[level]?.[week] || null;
  } catch(e) { return null; }
}

// ── Helper: Get level exam ─────────────────────────────────────
function getLevelExam(lang, level) {
  try {
    return SEA_LEVEL_EXAMS[lang]?.[level] || null;
  } catch(e) { return null; }
}

// ── Helper: Get week curriculum data ──────────────────────────
function getWeekData(lang, level, week) {
  try {
    return SEA_WEEKLY_CURRICULUM[lang]?.[level]?.weeks?.[week - 1] || null;
  } catch(e) { return null; }
}

// ── Helper: YouTube embed URL from video ID ────────────────────
function ytEmbed(videoId) {
  if (!videoId) return '';
  return `https://www.youtube.com/embed/${videoId}?rel=0&modestbranding=1`;
}

